-- Applications
hl.bind("SUPER + RETURN", hl.dsp.exec_cmd(SETTINGS .. "/terminal.sh"))
hl.bind("SUPER + SHIFT + B", hl.dsp.exec_cmd(browser))
hl.bind("SUPER + SHIFT + ALT + B", hl.dsp.exec_cmd(browser .. " --private"))
hl.bind("SUPER + SHIFT + E", hl.dsp.exec_cmd(filemanager))
hl.bind("SUPER + SHIFT + S", hl.dsp.exec_cmd("spotify"))
hl.bind("SUPER + SPACE", hl.dsp.exec_cmd(SCRIPTS .. "/launcher.sh"))
hl.bind("SUPER + CTRL + E", hl.dsp.exec_cmd(SCRIPTS .. "/launcher.sh -m symbols"))

-- Actions
hl.bind("SUPER + CTRL + R", hl.dsp.exec_cmd("hyprctl reload"))
hl.bind("SUPER + CTRL + Q", hl.dsp.exec_cmd(SCRIPTS .. "/wlogout.sh"))
hl.bind("SUPER + CTRL + K", hl.dsp.exec_cmd(SCRIPTS .. "/keybindings.sh"))
hl.bind("SUPER + CTRL + B", hl.dsp.exec_cmd("pkill waybar && hyprctl dispatch exec waybar"))
hl.bind("SUPER + CTRL + L", hl.dsp.exec_cmd("hyprlock"))
hl.bind("SUPER + escape", hl.dsp.exec_cmd(SCRIPTS .. "/menu.sh system"))
hl.bind("SUPER + SHIFT + CTRL + V", hl.dsp.exec_cmd(SCRIPTS .. "/toggle_vpn.sh"))

-- Display
hl.bind("SUPER + SHIFT + mouse_down", hl.dsp.exec_cmd("hyprctl keyword cursor:zoom_factor $(awk \"BEGIN {print $(hyprctl getoption cursor:zoom_factor | grep 'float:' | awk '{print " .. _2 .. "}') + 0.5}\")"))
hl.bind("SUPER + SHIFT + mouse_up", hl.dsp.exec_cmd("hyprctl keyword cursor:zoom_factor $(awk \"BEGIN {print $(hyprctl getoption cursor:zoom_factor | grep 'float:' | awk '{print " .. _2 .. "}') - 0.5}\")"))
hl.bind("SUPER + SHIFT + Z", hl.dsp.exec_cmd("hyprctl keyword cursor:zoom_factor 1"))
hl.bind("SUPER + BACKSPACE", hl.dsp.exec_cmd("hyprctl dispatch setprop \"address:$(hyprctl activewindow -j | jq -r '.address')\" opaque toggle"))

-- Windows
-- Close Windows
hl.bind("SUPER + W", hl.dsp.window.close())
hl.bind("SUPER + SHIFT + W", hl.dsp.exec_cmd("hyprctl activewindow | grep pid | tr -d 'pid:' | xargs kill"))

-- Tiling
hl.bind("SUPER + P", hl.dsp.window.pseudo())
hl.bind("SUPER + T", hl.dsp.window.float({ action = "toggle" }))
hl.bind("SUPER + SHIFT + F", hl.dsp.window.fullscreen(1))
hl.bind("SUPER + ALT + F", hl.dsp.window.fullscreen(0))

-- Move focus with SUPER + arrow
hl.bind("SUPER + H", hl.dsp.focus({ direction = "left" }))
hl.bind("SUPER + J", hl.dsp.focus({ direction = "down" }))
hl.bind("SUPER + K", hl.dsp.focus({ direction = "up" }))
hl.bind("SUPER + L", hl.dsp.focus({ direction = "right" }))

-- Swap active window with one next to it with SUPER + SHIFT + arrow keys
hl.bind("SUPER + SHIFT + H", hl.dsp.window.swap("l"))
hl.bind("SUPER + SHIFT + J", hl.dsp.window.swap("d"))
hl.bind("SUPER + SHIFT + K", hl.dsp.window.swap("u"))
hl.bind("SUPER + SHIFT + L", hl.dsp.window.swap("r"))

