-- Resize
hl.bind("SUPER + CTRL + right", hl.dsp.window.resize("100 0"))
hl.bind("SUPER + CTRL + left", hl.dsp.window.resize("-100 0"))
hl.bind("SUPER + CTRL + down", hl.dsp.window.resize("0 100"))
hl.bind("SUPER + CTRL + up", hl.dsp.window.resize("0 -100"))

-- Captures
hl.bind("SUPER + CTRL + 3", hl.dsp.exec_cmd(SCRIPTS .. "/screenshot.sh smart clipboard"))
hl.bind("SUPER + CTRL + 4", hl.dsp.exec_cmd(SCRIPTS .. "/screenshot.sh"))
hl.bind("SUPER + CTRL + 5", hl.dsp.exec_cmd(SCRIPTS .. "/screenshot.sh fullscreen"))
hl.bind("SUPER + CTRL + 6", hl.dsp.exec_cmd(SCRIPTS .. "/screenrecord.sh"))

-- Copy / Paste
hl.bind("SUPER + C", hl.dsp.send_shortcut("CTRL, Insert, "))
hl.bind("SUPER + V", hl.dsp.send_shortcut("SHIFT, Insert, "))
hl.bind("SUPER + X", hl.dsp.send_shortcut("CTRL, X, "))
-- bindd = SUPER CTRL, V, Clipboard manager, exec, omarchy-launch-walker -m clipboard

